function Toast({ msg, type }) {
  if (!msg) return null;
  return (
    <div style={{ position:"fixed",bottom:24,left:"50%",transform:"translateX(-50%)",background:type==="error"?"#7f1d1d":"#0d2d1f",color:type==="error"?"#fca5a5":"#4ade80",padding:"12px 24px",borderRadius:12,fontSize:14,fontWeight:600,zIndex:9999,boxShadow:"0 8px 32px rgba(0,0,0,.5)",whiteSpace:"nowrap",animation:"fadeUp .25s ease" }}>
      {msg}
      <style>{`@keyframes fadeUp{from{opacity:0;transform:translateX(-50%) translateY(12px)}to{opacity:1;transform:translateX(-50%) translateY(0)}}`}</style>
    </div>
  );
}

function BadgePill({ label, absolute=true }) {
  if (!label) return null;
  const c = BADGE_STYLE[label] || { bg:"#1a1a1a", tx:"#aaa" };
  return (
    <span style={{ background:c.bg,color:c.tx,fontSize:10,fontWeight:700,letterSpacing:"0.08em",padding:"3px 8px",borderRadius:99,textTransform:"uppercase",...(absolute?{position:"absolute",top:12,left:12}:{display:"inline-block"}) }}>
      {label}
    </span>
  );
}

function ImagePicker({ value, onChange }) {
  const fileRef = useRef(null);
  const [loading, setLoading] = useState(false);

  const handleFile = async (e) => {
    const file = e.target.files?.[0];
    if (!file || !file.type.startsWith("image/")) return;
    setLoading(true);
    try { onChange(await compressImage(file)); } catch {}
    setLoading(false);
    e.target.value = "";
  };

  return (
    <div>
      <label style={{ color:"#888",fontSize:12,fontWeight:600,textTransform:"uppercase",letterSpacing:"0.06em",display:"block",marginBottom:8 }}>Product image</label>
      <div style={{ width:"100%",aspectRatio:"16/9",borderRadius:12,overflow:"hidden",background:"#0e0e0e",border:"1.5px dashed #2a2a2a",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",position:"relative",marginBottom:12 }}>
        {loading ? (
          <div style={{ display:"flex",flexDirection:"column",alignItems:"center",gap:10 }}>
            <div style={{ width:32,height:32,border:"3px solid #222",borderTopColor:STORE.green,borderRadius:"50%",animation:"spin .7s linear infinite" }}/>
            <p style={{ color:"#555",fontSize:13,margin:0 }}>Compressing…</p>
            <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
          </div>
        ) : value ? (
          <>
            <img src={value} alt="preview" onError={e=>e.target.src=FALLBACK} style={{ width:"100%",height:"100%",objectFit:"cover" }}/>
            <button onClick={()=>onChange("")} style={{ position:"absolute",top:8,right:8,width:28,height:28,borderRadius:"50%",background:"rgba(0,0,0,.75)",border:"1px solid #444",color:"#fff",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center" }}><XIcon/></button>
          </>
        ) : (
          <div style={{ textAlign:"center",padding:24 }}>
            <div style={{ fontSize:32,marginBottom:8 }}>🖼️</div>
            <p style={{ color:"#555",fontSize:13,margin:0 }}>No image selected</p>
            <p style={{ color:"#444",fontSize:12,margin:"4px 0 0" }}>Upload from gallery or pick a random one</p>
          </div>
        )}
      </div>
      <div style={{ display:"flex",gap:10 }}>
        <button onClick={()=>fileRef.current?.click()} style={{ flex:1,display:"flex",alignItems:"center",justifyContent:"center",gap:7,background:"#141414",border:"1.5px solid #2a2a2a",color:"#ccc",fontSize:13,fontWeight:600,padding:"10px 0",borderRadius:10,cursor:"pointer" }} onMouseEnter={e=>{e.currentTarget.style.borderColor="#444";e.currentTarget.style.color="#fff"}} onMouseLeave={e=>{e.currentTarget.style.borderColor="#2a2a2a";e.currentTarget.style.color="#ccc"}}>
          <UploadIcon/> Pick from gallery
        </button>
        <button onClick={()=>onChange(randImg())} style={{ flex:1,display:"flex",alignItems:"center",justifyContent:"center",gap:7,background:"#141414",border:"1.5px solid #2a2a2a",color:"#ccc",fontSize:13,fontWeight:600,padding:"10px 0",borderRadius:10,cursor:"pointer" }} onMouseEnter={e=>{e.currentTarget.style.borderColor="#444";e.currentTarget.style.color="#fff"}} onMouseLeave={e=>{e.currentTarget.style.borderColor="#2a2a2a";e.currentTarget.style.color="#ccc"}}>
          <DiceIcon/> Random image
        </button>
      </div>
      <input ref={fileRef} type="file" accept="image/*" style={{ display:"none" }} onChange={handleFile}/>
    </div>
  );
}

